export const getTafseerSurahAsset = (tafseerKey, surahId) => {
  // Return the getter function itself — tafseerDb.js will call it.
  // Previously this called getter() here and returned the raw module ID,
  // causing "assetGetter is not a function" in tafseerDb.js.
  return TAFSEER_ASSET_MAP[`${tafseerKey}_${surahId}`] || null;
};
